+fn terminal_state_screen_text(state: &TerminalState) -> String {
+    (0..state.height())
+        .map(|y| {
+            let mut row = String::with_capacity(usize::from(state.width()));
+            for x in 0..state.width() {
+                let ch = state.cell(x, y).map_or(' ', |cell| cell.ch);
+                row.push(ch);
+            }
+            row.trim_end().to_string()
+        })
+        .collect::<Vec<_>>()
+        .join("\n")
+}
